using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Setup: a source-gen context that only knows about `Order` ---------
var options = new JsonSerializerOptions
{
    TypeInfoResolver = AppJsonContext.Default
};

// 1️⃣  Strongly-typed metadata — returns JsonTypeInfo<T> directly
JsonTypeInfo<Order> orderInfo = options.GetTypeInfo<Order>();
Console.WriteLine($"Got typed metadata for: {orderInfo.Type.Name}");

var json = JsonSerializer.Serialize(new Order(42, "Widget"), orderInfo);
Console.WriteLine($"Serialized: {json}");

// 2️⃣  Probe without throwing — TryGetTypeInfo returns false when
//     the resolver doesn't know about the type.
if (options.TryGetTypeInfo(typeof(Order), out JsonTypeInfo? found))
    Console.WriteLine($"TryGet  Order  → found ({found!.Type.Name})");
else
    Console.WriteLine("TryGet  Order  → not found");

if (options.TryGetTypeInfo(typeof(Customer), out JsonTypeInfo? notFound))
    Console.WriteLine($"TryGet Customer → found ({notFound!.Type.Name})");
else
    Console.WriteLine("TryGet Customer → not found  (no exception!)");

// --- Types & source-gen context ----------------------------------------
public record Order(int Id, string Product);
public record Customer(string Name);

[JsonSerializable(typeof(Order))]          // only Order is registered
[JsonSourceGenerationOptions(WriteIndented = false)]
public partial class AppJsonContext : JsonSerializerContext;

